const body = $input.first().json.body || {};
const headers = $input.first().json.headers || {};

return [{
  json: {
    ...body,
    _headers: headers,
    _startTime: startTime,
    _requestId: 'req_' + startTime + '_' + Math.random().toString(36).substr(2, 9)
  }
}];

