// ============================================
// STEP: Validate all inputs thoroughly
// ============================================
const data = $input.first().json;
const extractedData = data.extracted_data || '';
const sessionId = data.sessionId || '';
const requestId = data._requestId;

const errors = [];

// Check required fields
if (!extractedData || extractedData.trim().length === 0) {
  errors.push('extracted_data is required and cannot be empty');
}
if (!sessionId || sessionId.trim().length === 0) {
  errors.push('sessionId is required');
}

// Check length limits (prevent abuse)
if (extractedData.length > 50000) {
  errors.push('extracted_data exceeds maximum length of 50,000 characters');
}
if (extractedData.length < 10) {
  errors.push('extracted_data is too short to be a valid medical document');
}

// Sanitize sessionId (alphanumeric + hyphens only)
if (sessionId && !/^[a-zA-Z0-9_\-]{4,64}$/.test(sessionId)) {
  errors.push('sessionId must be 4-64 alphanumeric characters, hyphens, or underscores');
}

if (errors.length > 0) {
  return [{
    json: {
      _valid: false,
      _errors: errors,
      _requestId: requestId,
      _startTime: data._startTime
    }
  }];
}

// Hash sessionId for logging (never store raw session IDs)
const hashedSession = sessionId.split('').reduce((a, b) => {
  a = ((a << 5) - a) + b.charCodeAt(0);
  return a & a;
}, 0).toString(16);

return [{
  json: {
    _valid: true,
    _requestId: requestId,
    _startTime: data._startTime,
    _sessionHash: hashedSession,
    extracted_data: extractedData.trim(),
    sessionId: sessionId.trim(),
    report_length: extractedData.length
  }
}];

// ============================================
// STEP: Normalize output from either Gemini or Claude
// ============================================
const items = $input.all();
const item = items[0].json;

let analysisOutput = '';
let modelUsed = 'gemini';

// Check if this came from Claude fallback
if (item.content && Array.isArray(item.content)) {
  // Claude response format
  const textBlock = item.content.find(b => b.type === 'text');
  analysisOutput = textBlock ? textBlock.text : '';
  modelUsed = 'claude-fallback';
} else if (item.output) {
  // Gemini/agent response format
  analysisOutput = item.output;
  modelUsed = 'gemini';
} else {
  analysisOutput = '## ⚠️ Analysis Unavailable\n\nWe were unable to process your medical report at this time. Please try again in a few moments.\n\n*If this issue persists, please contact support.*';
  modelUsed = 'error';
}

const endTime = Date.now();
const latency = endTime - (item._startTime || endTime);

return [{
  json: {
    success: modelUsed !== 'error',
    output: analysisOutput,
    model_used: modelUsed,
    request_id: item._requestId || '',
    session_hash: item._sessionHash || '',
    latency_ms: latency,
    report_length: item.report_length || 0,
    response_length: analysisOutput.length,
    timestamp: new Date().toISOString(),
    _startTime: item._startTime,
    extracted_data: item.extracted_data || item.extracted_data
  }
}];
